def encrypt_data(data):
    secret_key = "your_secret_key_here"  # Replace with your secret key
    encrypted_data = hmac.new(secret_key.encode(), data.encode(), hashlib.sha256).digest()
    return base64.b64encode(encrypted_data)

def decrypt_data(encrypted_data):
    secret_key = "your_secret_key_here"  # Replace with your secret key
    decrypted_bytes = base64.b64decode(encrypted_data)
    return hmac.compare_digest(hmac.new(secret_key.encode(), b'original_data', hashlib.sha256).digest(), decrypted_bytes)

